(function(){
  var NW=1280,NH=720;
  function sf(){
    var f=document.getElementById('bb-tour');if(!f)return;
    var w=f.parentElement,bar=w.querySelector('.bb-bar'),bH=bar?bar.offsetHeight:44;
    var fs=w.classList.contains('bb-fullscreen'),aW=fs?window.innerWidth:w.clientWidth;
    var sc=fs?Math.min(aW/NW,(window.innerHeight-bH)/NH):aW/NW;
    f.style.width=NW+'px';f.style.height=NH+'px';
    f.style.transform='scale('+sc+')';f.style.transformOrigin='top left';
    f.style.marginBottom=Math.round(NH*(sc-1))+'px';
    f.style.marginLeft=fs?Math.max(0,Math.round((aW-NW*sc)/2))+'px':'0';
  }
  function tfs(){
    var f=document.getElementById('bb-tour'),w=f.parentElement,b=document.getElementById('bb-tour-fs');
    var fs=w.classList.toggle('bb-fullscreen');b.textContent=fs?'\u2715':'\u26F6';
    if(fs){window._bby=window.scrollY;document.body.style.overflow='hidden';}
    else{document.body.style.overflow='';window.scrollTo(0,window._bby||0);}sf();
  }
  sf();
  if(window._bbR)window.removeEventListener('resize',window._bbR);
  window._bbR=sf;window.addEventListener('resize',sf);
  if(window._bbK)document.removeEventListener('keydown',window._bbK);
  window._bbK=function(e){if(e.key==='Escape'){var f=document.getElementById('bb-tour');if(f&&f.parentElement.classList.contains('bb-fullscreen'))tfs();}};
  document.addEventListener('keydown',window._bbK);
  document.getElementById('bb-tour-fs').onclick=tfs;

})()

